 1	import { ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
 2	import * as React from 'react';
 3	import { useTranslation } from 'react-i18next';
 4	import {
 5	  DescriptionListDescription,
 6	  DescriptionListGroup,
 7	  DescriptionListTerm,
 8	} from '@patternfly/react-core';
 9	import {
10	  ConfigMapModel,
11	  PersistentVolumeClaimModel,
12	  SecretModel,
13	} from '../../models';
14	import {
15	  PipelineRunWorkspace,
16	  VolumeTypeConfigMaps,
17	  VolumeTypePVC,
18	  VolumeTypeSecret,
19	} from '../../types';
20	
21	type WorkspaceResourcesSectionProps = {
22	  namespace: string;
23	  workspaces: PipelineRunWorkspace[];
24	};
25	
26	const WorkspaceResourcesSection: React.FC<WorkspaceResourcesSectionProps> = ({
27	  namespace,
28	  workspaces,
29	}) => {
30	  const { t } = useTranslation('plugin__pipelines-console-plugin');
31	
32	  if (!namespace || !workspaces || workspaces.length === 0) return null;
33	
34	  const workspacesRenders = workspaces
35	    .map((workspace) => {
36	      if (workspace.persistentVolumeClaim) {
37	        const persistentVolumeClaim =
38	          workspace.persistentVolumeClaim as VolumeTypePVC;
39	        const displayName = `${persistentVolumeClaim.claimName} (${workspace.name})`;
40	        return (
41	          <ResourceLink
42	            key={workspace.name}
43	            name={persistentVolumeClaim.claimName}
44	            namespace={namespace}
45	            kind={PersistentVolumeClaimModel.kind}
46	            displayName={displayName}
47	          />
48	        );
49	      }
50	      if (workspace.configMap) {
51	        const configMap = workspace.configMap as VolumeTypeConfigMaps;
52	        const displayName = `${configMap.name} (${workspace.name})`;
53	        return (
54	          <ResourceLink
55	            key={workspace.name}
56	            name={configMap.name}
57	            namespace={namespace}
58	            kind={ConfigMapModel.kind}
59	            displayName={displayName}
60	          />
61	        );
62	      }
63	      if (workspace.secret) {
64	        const secret = workspace.secret as VolumeTypeSecret;
65	        const displayName = `${secret.secretName} (${workspace.name})`;
66	        return (
67	          <ResourceLink
68	            key={workspace.name}
69	            name={secret.secretName}
70	            kind={SecretModel.kind}
71	            namespace={namespace}
72	            displayName={displayName}
73	          />
74	        );
75	      }
76	      return null;
77	    })
78	    .filter((v) => !!v);
79	
80	  if (workspacesRenders.length === 0) return null;
81	
82	  return (
83	    <DescriptionListGroup data-test-id="workspace-resources-section">
84	      <DescriptionListTerm>{t('Workspace Resources')}</DescriptionListTerm>
85	      <DescriptionListDescription>
86	        {workspacesRenders}
87	      </DescriptionListDescription>
88	    </DescriptionListGroup>
89	  );
90	};
91	
92	export default WorkspaceResourcesSection;

